import { writable, derived } from 'svelte/store';
import { apiClient } from '../utils/api-client';
const initialState = {
    dashboard: null,
    userStats: null,
    systemHealth: null,
    trends: {
        summary: null,
        artists: [],
        platforms: [],
    },
    reportTypes: [],
    reports: [],
    currentReport: null,
    // Trouble scores
    troubleLeaderboard: [],
    tierDistribution: null,
    selectedArtistScore: null,
    // Revenue
    revenueDistribution: null,
    topArtistsByRevenue: [],
    problematicArtistRevenue: [],
    payoutRates: [],
    // Category Revenue (Simulated)
    globalCategoryRevenue: null,
    offenseCategories: [],
    selectedCategoryRevenue: null,
    artistDiscographyRevenue: null,
    isLoading: false,
    error: null,
};
// Store
export const analyticsStore = writable(initialState);
// Derived stores
export const isSystemHealthy = derived(analyticsStore, ($analytics) => $analytics.systemHealth?.overall === 'healthy');
export const risingArtists = derived(analyticsStore, ($analytics) => $analytics.trends.artists.filter(a => a.trend === 'rising'));
export const fallingArtists = derived(analyticsStore, ($analytics) => $analytics.trends.artists.filter(a => a.trend === 'falling'));
// Actions
export const analyticsActions = {
    fetchDashboard: async (timeRange = 'last7days') => {
        analyticsStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/dashboard?time_range=${timeRange}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    dashboard: result.data,
                    isLoading: false,
                }));
                return { success: true };
            }
            else {
                analyticsStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to fetch dashboard',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            analyticsStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    fetchUserStats: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/dashboard/user-stats');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    userStats: result.data,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchSystemHealth: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/health');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    systemHealth: result.data,
                }));
                return { success: true, health: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchTrendSummary: async (periodDays = 7) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/trends?period_days=${periodDays}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    trends: {
                        ...s.trends,
                        summary: result.data,
                    },
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchRisingArtists: async (limit = 10) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/trends/rising?limit=${limit}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    trends: {
                        ...s.trends,
                        artists: [
                            ...s.trends.artists.filter(a => a.trend !== 'rising'),
                            ...result.data.artists.map(a => ({ ...a, trend: 'rising' })),
                        ],
                    },
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchFallingArtists: async (limit = 10) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/trends/falling?limit=${limit}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    trends: {
                        ...s.trends,
                        artists: [
                            ...s.trends.artists.filter(a => a.trend !== 'falling'),
                            ...result.data.artists.map(a => ({ ...a, trend: 'falling' })),
                        ],
                    },
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchReportTypes: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/reports/types');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    reportTypes: result.data.report_types,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    generateReport: async (request) => {
        try {
            const result = await apiClient.authenticatedRequest('POST', '/api/v1/analytics/reports', request);
            if (result.success && result.data) {
                return { success: true, reportId: result.data.report_id };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchReportStatus: async (reportId) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/reports/${reportId}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    currentReport: result.data,
                }));
                return { success: true, report: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    clearError: () => {
        analyticsStore.update(s => ({ ...s, error: null }));
    },
    // Trouble Score Actions
    fetchTroubleLeaderboard: async (minTier, limit = 20, offset = 0) => {
        try {
            const params = new URLSearchParams({ limit: limit.toString(), offset: offset.toString() });
            if (minTier)
                params.append('min_tier', minTier);
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/trouble-scores/leaderboard?${params}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    troubleLeaderboard: result.data.entries,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchTierDistribution: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/trouble-scores/distribution');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    tierDistribution: result.data,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchArtistTroubleScore: async (artistId) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/trouble-scores/${artistId}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    selectedArtistScore: result.data,
                }));
                return { success: true, score: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    // Revenue Actions
    fetchRevenueDistribution: async (days = 30, platform) => {
        try {
            const params = new URLSearchParams({ days: days.toString() });
            if (platform)
                params.append('platform', platform);
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/revenue/distribution?${params}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    revenueDistribution: result.data,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchTopArtistsByRevenue: async (days = 30, limit = 10) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/revenue/top-artists?days=${days}&limit=${limit}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    topArtistsByRevenue: result.data.artists,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchProblematicArtistRevenue: async (days = 30, minTier = 'moderate', limit = 10) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/revenue/problematic?days=${days}&min_tier=${minTier}&limit=${limit}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    problematicArtistRevenue: result.data.artists,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchPayoutRates: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/revenue/payout-rates');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    payoutRates: result.data.rates,
                }));
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchArtistRevenue: async (artistId, days = 30) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/revenue/artist/${artistId}?days=${days}`);
            if (result.success && result.data) {
                return { success: true, breakdown: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    // Category Revenue Actions (Simulated by Offense Category)
    fetchGlobalCategoryRevenue: async () => {
        analyticsStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/category-revenue');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    globalCategoryRevenue: result.data,
                    isLoading: false,
                }));
                return { success: true, data: result.data };
            }
            else {
                analyticsStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to fetch category revenue',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            analyticsStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    fetchOffenseCategories: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/analytics/category-revenue/categories');
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    offenseCategories: result.data.categories,
                }));
                return { success: true, categories: result.data.categories };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchCategoryRevenue: async (category, topN = 10) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/category-revenue/${category}?top_n=${topN}`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    selectedCategoryRevenue: result.data,
                }));
                return { success: true, data: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchArtistDiscographyRevenue: async (artistId) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/category-revenue/artist/${artistId}/discography`);
            if (result.success && result.data) {
                analyticsStore.update(s => ({
                    ...s,
                    artistDiscographyRevenue: result.data,
                }));
                return { success: true, data: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchUserCategoryExposure: async (days = 30) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/analytics/category-revenue/user/exposure?days=${days}`);
            if (result.success && result.data) {
                return { success: true, categories: result.data.categories };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    clearCategoryRevenue: () => {
        analyticsStore.update(s => ({
            ...s,
            globalCategoryRevenue: null,
            selectedCategoryRevenue: null,
            artistDiscographyRevenue: null,
        }));
    },
};
