import { writable, derived } from 'svelte/store';
import { apiClient } from '../utils/api-client';
const initialState = {
    currentNetwork: null,
    selectedArtist: null,
    collaborators: [],
    pathResult: null,
    blockedAnalysis: null,
    health: null,
    stats: null,
    isLoading: false,
    isLoadingPath: false,
    error: null,
};
// Store
export const graphStore = writable(initialState);
// Derived stores
export const networkNodes = derived(graphStore, ($graph) => $graph.currentNetwork?.nodes ?? []);
export const networkEdges = derived(graphStore, ($graph) => $graph.currentNetwork?.edges ?? []);
export const blockedNodes = derived(graphStore, ($graph) => $graph.currentNetwork?.nodes.filter(n => n.is_blocked) ?? []);
export const atRiskArtists = derived(graphStore, ($graph) => $graph.blockedAnalysis?.at_risk_artists ?? []);
export const isGraphHealthy = derived(graphStore, ($graph) => $graph.health?.status === 'healthy');
// Actions
export const graphActions = {
    fetchArtistNetwork: async (artistId, depth = 2) => {
        graphStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/graph/artists/${artistId}/network?depth=${depth}`);
            if (result.success && result.data) {
                graphStore.update(s => ({
                    ...s,
                    currentNetwork: result.data,
                    isLoading: false,
                }));
                return { success: true };
            }
            else {
                graphStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to fetch artist network',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            graphStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    fetchCollaborators: async (artistId, limit = 20) => {
        graphStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/graph/artists/${artistId}/collaborators?limit=${limit}`);
            if (result.success && result.data) {
                graphStore.update(s => ({
                    ...s,
                    collaborators: result.data.collaborators,
                    isLoading: false,
                }));
                return { success: true };
            }
            else {
                graphStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to fetch collaborators',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            graphStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    findPath: async (sourceId, targetId) => {
        graphStore.update(s => ({ ...s, isLoadingPath: true, error: null, pathResult: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/graph/artists/${sourceId}/path-to/${targetId}`);
            if (result.success && result.data) {
                graphStore.update(s => ({
                    ...s,
                    pathResult: result.data,
                    isLoadingPath: false,
                }));
                return { success: true, path: result.data };
            }
            else {
                graphStore.update(s => ({
                    ...s,
                    isLoadingPath: false,
                    error: result.message || 'No path found',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            graphStore.update(s => ({
                ...s,
                isLoadingPath: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    analyzeBlockedNetwork: async () => {
        graphStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('POST', '/api/v1/graph/blocked-network');
            if (result.success && result.data) {
                graphStore.update(s => ({
                    ...s,
                    blockedAnalysis: result.data,
                    isLoading: false,
                }));
                return { success: true, analysis: result.data };
            }
            else {
                graphStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to analyze blocked network',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            graphStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    fetchHealth: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/graph/health');
            if (result.success && result.data) {
                graphStore.update(s => ({
                    ...s,
                    health: result.data,
                }));
                return { success: true, health: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchStats: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/graph/stats');
            if (result.success && result.data) {
                graphStore.update(s => ({
                    ...s,
                    stats: result.data,
                }));
                return { success: true, stats: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    selectArtist: (artist) => {
        graphStore.update(s => ({ ...s, selectedArtist: artist }));
    },
    clearNetwork: () => {
        graphStore.update(s => ({
            ...s,
            currentNetwork: null,
            collaborators: [],
            pathResult: null,
        }));
    },
    clearError: () => {
        graphStore.update(s => ({ ...s, error: null }));
    },
};
