import { writable, derived } from 'svelte/store';
import { apiClient } from '../utils/api-client';
const initialState = {
    status: [],
    runs: [],
    currentRun: null,
    health: null,
    canonicalArtists: [],
    isLoading: false,
    isTriggering: false,
    error: null,
};
// Store
export const syncStore = writable(initialState);
// Derived stores
export const isAnySyncRunning = derived(syncStore, ($sync) => $sync.status.some(s => s.status === 'running'));
export const platformsStatus = derived(syncStore, ($sync) => $sync.status);
export const recentRuns = derived(syncStore, ($sync) => $sync.runs.slice(0, 10));
// Actions
export const syncActions = {
    fetchStatus: async () => {
        syncStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/sync/status');
            if (result.success && result.data) {
                syncStore.update(s => ({
                    ...s,
                    status: result.data.platforms,
                    isLoading: false,
                }));
                return { success: true };
            }
            else {
                syncStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to fetch sync status',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            syncStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    triggerSync: async (request) => {
        syncStore.update(s => ({ ...s, isTriggering: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('POST', '/api/v1/sync/trigger', request);
            if (result.success && result.data) {
                syncStore.update(s => ({ ...s, isTriggering: false }));
                // Refresh status after triggering
                await syncActions.fetchStatus();
                await syncActions.fetchRuns();
                return { success: true, runId: result.data.run_id };
            }
            else {
                syncStore.update(s => ({
                    ...s,
                    isTriggering: false,
                    error: result.message || 'Failed to trigger sync',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            syncStore.update(s => ({
                ...s,
                isTriggering: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    fetchRuns: async (limit = 20) => {
        syncStore.update(s => ({ ...s, isLoading: true, error: null }));
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/sync/runs?limit=${limit}`);
            if (result.success && result.data) {
                syncStore.update(s => ({
                    ...s,
                    runs: result.data.runs,
                    isLoading: false,
                }));
                return { success: true };
            }
            else {
                syncStore.update(s => ({
                    ...s,
                    isLoading: false,
                    error: result.message || 'Failed to fetch sync runs',
                }));
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            syncStore.update(s => ({
                ...s,
                isLoading: false,
                error: error.message || 'Network error',
            }));
            return { success: false, message: error.message };
        }
    },
    fetchRun: async (runId) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/sync/runs/${runId}`);
            if (result.success && result.data) {
                syncStore.update(s => ({
                    ...s,
                    currentRun: result.data,
                }));
                return { success: true, run: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    cancelRun: async (runId) => {
        try {
            const result = await apiClient.authenticatedRequest('POST', `/api/v1/sync/runs/${runId}/cancel`);
            if (result.success) {
                await syncActions.fetchRuns();
                return { success: true };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    fetchHealth: async () => {
        try {
            const result = await apiClient.authenticatedRequest('GET', '/api/v1/sync/health');
            if (result.success && result.data) {
                syncStore.update(s => ({
                    ...s,
                    health: result.data,
                }));
                return { success: true, health: result.data };
            }
            else {
                return { success: false, message: result.message };
            }
        }
        catch (error) {
            return { success: false, message: error.message };
        }
    },
    searchArtists: async (query) => {
        try {
            const result = await apiClient.authenticatedRequest('GET', `/api/v1/sync/search?q=${encodeURIComponent(query)}`);
            if (result.success && result.data) {
                return { success: true, artists: result.data.artists };
            }
            else {
                return { success: false, message: result.message, artists: [] };
            }
        }
        catch (error) {
            return { success: false, message: error.message, artists: [] };
        }
    },
    clearError: () => {
        syncStore.update(s => ({ ...s, error: null }));
    },
};
